import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"咆哮的温彻斯特","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/0.无支线/咆哮的温彻斯特.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/0.无支线/咆哮的温彻斯特.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/远程武器/0.无支线/咆哮的温彻斯特.md"};function _(l,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"咆哮的温彻斯特",tabindex:"-1"},[s("咆哮的温彻斯特 "),e("a",{class:"header-anchor",href:"#咆哮的温彻斯特","aria-label":'Permalink to "咆哮的温彻斯特"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001C")])])],-1),o('<h1 id="咆哮的温彻斯特-1" tabindex="-1">咆哮的温彻斯特 <a class="header-anchor" href="#咆哮的温彻斯特-1" aria-label="Permalink to &quot;咆哮的温彻斯特&quot;">​</a></h1><p>咆哮的温彻斯特<br> 750<br> 特异本质<br> 武器伤害4L 装弹数11+1 射程40米<br> 攻击距离不超过10米内的单位时获得2威猛<br> 咆哮的温彻斯特是一把枪身锈迹斑驳的老式霰弹枪，它在被使用时会发出令人恐惧的、如同咆哮般的枪声，这意味着它即使安装消音器也不能发挥其效力。<br> 咆哮的温彻斯特的枪柄上有用刀刻下的划痕，枪的前任主人在战场上每击毙一名敌人，就会刻下一道划痕记录战功。而它在每场影片结束后都会再自然的浮现出一道划痕，这些划痕的初始为零条，它每拥有一条划痕，就会在使用咆哮的温彻斯特进行射击时再提供1DP士气加值。<br> 特殊的，咆哮的温彻斯特也可以作为物品改造的模板使用，花费对应的分数，将此霰弹枪模板移植至其他霰弹枪上，这不会使它的武器伤害被继承，而是会正常提供其效果和已有的配件改装。<br> 咆哮的温彻斯特可以正常进行枪械改装，每项25分的改装使用250分，每项50分的改装使用500分，仍然遵循改装规则，此时它视为现实霰弹枪价格。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
